class Solution:
    def countSpecialNumbers(self, n):
        digits = list(map(int, str(n)))
        L = len(digits)
        def perm(m, k):
            r = 1
            for i in range(k):
                r *= (m - i)
            return r
        total = 0
        for length in range(1, L):
            total += 9 * perm(9, length - 1)
        used = set()
        for i, d in enumerate(digits):
            start = 1 if i == 0 else 0
            for c in range(start, d):
                if c in used:
                    continue
                total += perm(9 - i, L - i - 1)
            if d in used:
                break
            used.add(d)
        else:
            total += 1
        return total

